#!/bin/bash

# Check for all error events in the hooksmith events log
# Usage: ./scripts/check-errors.sh

echo "🔍 Checking for error events in hooksmith-events.jsonl..."
echo ""

# Count total events
total_events=$(wc -l < hooksmith-events.jsonl 2>/dev/null || echo "0")
error_events=$(grep -c '"severity":"Error"' hooksmith-events.jsonl 2>/dev/null || echo "0")

echo "📊 Event Statistics:"
echo "   Total events: $total_events"
echo "   Error events: $error_events"
echo ""

if [ "$error_events" -gt 0 ]; then
    echo "🚨 Error Events Found:"
    echo ""
    
    # Show all error events with details
    grep '"severity":"Error"' hooksmith-events.jsonl | while read line; do
        timestamp=$(echo "$line" | jq -r '.timestamp' 2>/dev/null)
        event_type=$(echo "$line" | jq -r '.event_type' 2>/dev/null)
        message=$(echo "$line" | jq -r '.message' 2>/dev/null)
        source=$(echo "$line" | jq -r '.source' 2>/dev/null)
        
        echo "   📅 $timestamp"
        echo "   🔧 Type: $event_type"
        echo "   📍 Source: $source"
        echo "   💬 Message: $message"
        echo ""
    done
else
    echo "✅ No error events found!"
fi 
